parameters.jsCode:
const text = ($json.user_text || '').trim();

return {
  json: {
    platform: $json.platform,
    session_id: String($json.session_id),
    chat_id: String($json.chat_id),
    user_id: String($json.user_id),
    username: $json.username || 'player',
    message_id: $json.message_id,
    user_text: text,
    turn: {
      input_text: text,
      input_type: text.startsWith('/') ? 'command' : 'story',
      command: text.startsWith('/') ? text.split(' ')[0].toLowerCase() : null,
      command_args: text.startsWith('/') ? text.split(' ').slice(1).join(' ') : null
    },
    meta: {
      source_type: $json.source_type,
      telegram_date: $json.telegram_date,
      run_ts: $json.run_ts
    }
  }
};

const memories = items.map(item => item.json);

const memoryLines = memories.map((m, index) => {
  const type = m.memory_type || 'memory';
  const importance = m.importance ?? 0;
  const content = m.content || '';
  return `[${index + 1}] (${type}, importance=${importance}) ${content}`;
});

return [
  {
    json: {
      session_id: $('session_with_turn').item.json.session_id,
      memory_count: memories.length,
      memory_block: memoryLines.length
        ? memoryLines.join('\n')
        : 'Нет сохранённой памяти.'
    }
  }
];

const sessionId = String($json.session_id || '');
const chatId = String($json.chat_id || '');
const userId = String($json.user_id || '');
const username = String($json.username || 'player');
const userText = String($json.user_text || '').trim();
const currentScene = String($json.current_scene || 'intro_pending');
const isInitialized = Boolean($json.is_initialized);

function limitText(value, maxLen) {
  const text = String(value || '').trim();
  if (!text) return '';
  return text.length > maxLen ? text.slice(0, maxLen) + '\n...[truncated]' : text;
}

const worldBible = limitText($json.world_bible_block || 'Лор мира пока не загружен.', 8000);
const summaryText = limitText($json.summary_text || 'Нет краткого summary.', 2500);
const dialogueBlock = limitText($json.dialogue_block || 'Нет предыдущих ходов.', 3500);
const memoryBlock = limitText($json.memory_block || 'Нет сохранённой памяти.', 2500);
const worldStateBlock = limitText($json.world_state_block || 'Мировое состояние пока пустое.', 3500);


const systemPrompt = [
  'Ты — ведущий повествовательной текстовой ролевой игры.',
  'Пиши только на русском языке. Никогда не вставляй английские, латинские или транслитерированные слова в основной текст. Если нужно иностранное название — переведи или замени русским аналогом.',
  'Пиши только от второго лица: "ты".',
  'Игрок полностью управляет только Дэниалом. Никогда не пиши реплики, действия, решения, выборы или мысли за Дэниала. Не продолжай его фразы. Не дописывай за него.',
  'Если игрок написал действие или реплику — считай, что оно уже произошло, и описывай только последствия: реакцию мира, NPC, угроз, окружения, Системы, Созвездий и Ведущих.',
  'Управляй только миром, NPC, врагами, окружением, последствиями, Системой и сценой.',
  'Стиль: мрачный, кинематографичный, напряжённый, реалистичный, жёсткий. Не смягчай атмосферу и не морализируй. Не превращай сцену в бессмысленную мясорубку.',
  'Сохраняй причинно-следственную связь и внутреннюю логику мира из блока [WORLD_BIBLE].',
  'Строго следуй блоку [WORLD_BIBLE]. Это канон. Не противоречь ему и не вводи сущности, которые ему противоречат.',
  'Запрещено использовать любое декоративное форматирование: никаких звёздочек, двойных звёздочек, подчёркиваний, обратных кавычек, символов решётки, квадратных скобок-заголовков, Markdown и HTML-тегов. Пиши цельным художественным текстом.',
  'Системные уведомления, реплики Ведущего и реакции Созвездий подавай как отдельные короткие блоки внутри повествования, без Markdown, без звёздочек, без английских слов.',
  'Не задавай прямой вопрос в духе "что ты делаешь?", "что дальше?", "куда ты пойдёшь?" в конце ответа. Завершай ответ открытой ситуацией, а не вопросом игроку.',
  'Не предлагай список вариантов действий.'
].join('\n');


const openingDirective = !isInitialized
  ? [
      '[OPENING_DIRECTIVE]',
      'Это первый ход новой сессии. Сейчас ты обязан начать сцену строго по разделу ## OPENING_SCENE из [WORLD_BIBLE].',
      'Запрещено выдумывать другое место, других существ, другие обстоятельства начала шоу.',
      'Дэниал должен оказаться среди огромной толпы людей (около тысячи человек) в крупном современном городе 2030 года, в обычной городской локации (площадь, торговый центр, метро, кампус, стадион, развязка).',
      'Над толпой небо должно треснуть тонкой светящейся линией. В небе или над землёй должен появиться маленький разлом. Из разлома должно вылететь существо размером с кошку, похожее на плюшевую игрушку с большими глазами и невозможной улыбкой.',
      'Перед лицом каждого человека, включая Дэниала, должен появиться личный системный экран с приветствием.',
      'Запрещено: руины, апокалипсис, амнезия, "ты не помнишь", разрушенные здания, сектора с номерами, активированные контракты, именованные Созвездия, голоса в голове, выданные задания. Ничего этого в первой сцене быть не должно. Мир ещё обычный, и трещина в небе — первое аномальное событие.',
      'Не пиши за Дэниала действий, реплик, решений и мыслей. Завершай сцену моментом, в котором игрок делает свой первый ход.'
    ].join('\n') + '\n\n'
  : '';

const contextBlock = openingDirective + [
  '[WORLD_BIBLE]',
  worldBible,
  '',
  '[SESSION_ID]',
  sessionId,
  '',
  '[PLAYER]',
  username,
  '',
  '[CURRENT_SCENE]',
  currentScene,
  '',
  '[IS_INITIALIZED]',
  String(isInitialized),
  '',
  '[SUMMARY]',
  summaryText,
  '',
  '[RECENT_TURNS]',
  dialogueBlock,
  '',
  '[MEMORY]',
  memoryBlock,
  '',
  '[WORLD_STATE]',
  worldStateBlock,
  '',
  '[LATEST_USER_INPUT]',
  userText
].join('\n');
return {
  json: {
    session_id: sessionId,
    chat_id: chatId,
    user_id: userId,
    username: username,
    user_text: userText,
    prompt_payload: {
      system: systemPrompt,
      context: contextBlock,
      user: userText
    }
  }
};

const response =
  $json.text ||
  $json.response ||
  $json.output ||
  $json.output_text ||
  $json.content ||
  '';

return {
  json: {
    session_id: $('build_prompt_payload').item.json.session_id,
    chat_id: $('build_prompt_payload').item.json.chat_id,
    user_id: $('build_prompt_payload').item.json.user_id,
    username: $('build_prompt_payload').item.json.username,
    user_text: $('build_prompt_payload').item.json.user_text,
    assistant_text: Array.isArray(response) ? response.join('\n') : String(response).trim()
  }
};

