UPDATE game_sessions
SET
  player_name = '{{ $("Code in JavaScript").item.json.username }}',
  current_scene = 'intro_pending',
  state_json = '{{ JSON.stringify({
    player: {
      name: "Дэниал",
      injuries: [],
      inventory: [],
      status_effects: [],
      contracts: []
    },
    world: {
      location: null,
      time_of_day: null,
      weather: null,
      danger_level: 0
    },
    scene: {
      title: null,
      situation: null
    },
    meta: {
      turn_count: 0
    }
  }) }}',
  summary_text = '',
  is_initialized = false,
  updated_at = NOW()
WHERE session_id = '{{ $("Code in JavaScript").item.json.session_id }}'
RETURNING
  session_id,
  player_name,
  current_scene,
  is_initialized,
  updated_at;

parameters.jsCode:
const raw = String($json.assistant_text || '').trim();

const safeText = raw.length > 3800
  ? raw.slice(0, 3800).trim() + '\n\n[сообщение обрезано]'
  : raw;

return {
  json: {
    session_id: $json.session_id,
    chat_id: $json.chat_id,
    user_id: $json.user_id,
    username: $json.username,
    user_text: $json.user_text,
    assistant_text: $json.assistant_text,
    telegram_text: safeText
  }
};

let state = {};

try {
  state = typeof $json.state_json === 'string'
    ? JSON.parse($json.state_json)
    : ($json.state_json || {});
} catch {
  state = {};
}

state.player = state.player || {
  name: 'Дэниал',
  injuries: [],
  inventory: [],
  status_effects: [],
  contracts: []
};

state.world = state.world || {
  location: null,
  time_of_day: null,
  weather: null,
  danger_level: 0
};

state.scene = state.scene || {
  title: null,
  situation: null
};

state.meta = state.meta || {};

state.meta.last_user_text = $json.user_text || '';
state.meta.last_assistant_text = $json.assistant_text || '';
state.meta.last_turn_at = new Date().toISOString();

return {
  json: {
    session_id: $json.session_id,
    next_state_json: JSON.stringify(state)
  }
};

const turns = items.map(item => item.json).reverse();

const dialogueBlock = turns.length
  ? turns.map((t, i) => {
      const userText = t.user_text || '';
      const assistantText = t.assistant_text || '';
      return `[Ход ${i + 1}]
Игрок: ${userText}
ИИ: ${assistantText}`;
    }).join('\n\n')
  : 'Нет предыдущих ходов.';

return [
  {
    json: {
      session_id: $('session_with_turn').item.json.session_id,
      recent_turns_count: turns.length,
      dialogue_block: dialogueBlock
    }
  }
];

const userText = String($json.user_text || '').trim();
const assistantText = String($json.assistant_text || '').trim();

const shortAssistant = assistantText.length > 500
  ? assistantText.slice(0, 500).trim() + '...'
  : assistantText;

let importance = 3;

if (userText.startsWith('/')) importance = 1;
if (assistantText.includes('контракт') || assistantText.includes('Созвезд')) importance = 4;
if (assistantText.includes('травм') || assistantText.includes('кров') || assistantText.includes('смерт')) importance = 4;
if (assistantText.includes('задание') || assistantText.includes('система')) importance = 4;

return {
  json: {
    session_id: $json.session_id,
    memory_type: 'turn',
    memory_content: `Игрок: ${userText} | ИИ: ${shortAssistant}`,
    memory_importance: importance
  }
};

const lore = items.map(item => item.json);

const isInitialized = Boolean($('session_with_turn').item.json.is_initialized);

const filtered = lore.filter(entry => {
  if (entry.category === 'OPENING_SCENE') return !isInitialized;
  return true;
});

const grouped = {};
for (const entry of filtered) {
  const category = entry.category || 'GENERAL';
  if (!grouped[category]) grouped[category] = [];
  grouped[category].push(entry);
}

const categoryOrder = [
  'CORE_RULES',
  'SETTING',
  'PROTAGONIST',
  'PLAYER_ACTIONS',
  'RESPONSE_FORMAT',
  'STARTING_FOCUS',
  'MEMORY_RULES',
  'SYSTEM',
  'HOSTS',
  'CONSTELLATIONS',
  'RACES',
  'ARTIFACTS',
  'ITEMS',
  'OPENING_SCENE'
];


const allCategories = Object.keys(grouped);
const ordered = [
  ...categoryOrder.filter(c => allCategories.includes(c)),
  ...allCategories.filter(c => !categoryOrder.includes(c))
];

const blocks = ordered.map(category => {
  const entries = grouped[category]
    .sort((a, b) => (b.priority ?? 0) - (a.priority ?? 0))
    .map(e => `- ${e.title}: ${e.content}`)
    .join('\n');
  return `## ${category}\n${entries}`;
});

const worldBibleBlock = blocks.length
  ? blocks.join('\n\n')
  : 'Лор мира пока не загружен.';

return [
  {
    json: {
      world_bible_block: worldBibleBlock,
      world_bible_count: filtered.length,
      is_initialized: isInitialized
    }
  }
];

