parameters.jsCode:
const npcs = $input.all(0).map(i => i.json);
const constellations = $input.all(1).map(i => i.json);
const hosts = $input.all(2).map(i => i.json);
const contracts = $input.all(3).map(i => i.json);

function packNpcs(rows) {
  if (!rows.length) return 'Нет известных NPC.';
  return rows.map(n => {
    const parts = [];
    parts.push(`- ${n.name}`);
    if (n.role) parts.push(`роль: ${n.role}`);
    if (n.faction) parts.push(`фракция: ${n.faction}`);
    if (n.relation) parts.push(`отношение: ${n.relation}`);
    if (n.status) parts.push(`статус: ${n.status}`);
    if (n.last_scene) parts.push(`последняя сцена: ${n.last_scene}`);
    if (n.notes) parts.push(`заметки: ${n.notes}`);
    return parts.join(' | ');
  }).join('\n');
}

function packConstellations(rows) {
  if (!rows.length) return 'Ни одно Созвездие пока не проявилось.';
  return rows.map(c => {
    const parts = [];
    parts.push(`- ${c.name}`);
    if (c.sphere) parts.push(`сфера: ${c.sphere}`);
    if (c.attitude) parts.push(`отношение: ${c.attitude}`);
    if (c.first_seen_scene) parts.push(`первое появление: ${c.first_seen_scene}`);
    if (c.notes) parts.push(`заметки: ${c.notes}`);
    return parts.join(' | ');
  }).join('\n');
}

function packHosts(rows) {
  if (!rows.length) return 'Ведущие пока не известны.';
  return rows.map(h => {
    const parts = [];
    parts.push(`- ${h.name}`);
    if (h.sector) parts.push(`сектор: ${h.sector}`);
    if (h.rank) parts.push(`ранг: ${h.rank}`);
    if (h.attitude) parts.push(`отношение: ${h.attitude}`);
    if (h.notes) parts.push(`заметки: ${h.notes}`);
    return parts.join(' | ');
  }).join('\n');
}

function packContracts(rows) {
  if (!rows.length) return 'Активных контрактов нет.';
  return rows.map(c => {
    const parts = [];
    parts.push(`- ${c.title}`);
    if (c.constellation) parts.push(`от: ${c.constellation}`);
    if (c.status) parts.push(`статус: ${c.status}`);
    if (c.conditions) parts.push(`условия: ${c.conditions}`);
    if (c.rewards) parts.push(`награды: ${c.rewards}`);
    if (c.notes) parts.push(`заметки: ${c.notes}`);
    return parts.join(' | ');
  }).join('\n');
}

const worldStateBlock = [
  '### NPC',
  packNpcs(npcs),
  '',
  '### CONSTELLATIONS',
  packConstellations(constellations),
  '',
  '### HOSTS',
  packHosts(hosts),
  '',
  '### CONTRACTS',
  packContracts(contracts)
].join('\n');

return [
  {
    json: {
      world_state_block: worldStateBlock,
      world_state_counts: {
        npcs: npcs.length,
        constellations: constellations.length,
        hosts: hosts.length,
        contracts: contracts.length
      }
    }
  }
];

const raw = String(
  $json.text ||
  $json.response ||
  $json.output ||
  $json.output_text ||
  $json.content ||
  ''
).trim();

let parsed = { npcs: [], constellations: [], hosts: [], contracts: [] };

if (raw) {
  let candidate = raw;

  const fenceMatch = candidate.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fenceMatch) candidate = fenceMatch[1].trim();

  const firstBrace = candidate.indexOf('{');
  const lastBrace = candidate.lastIndexOf('}');
  if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
    candidate = candidate.slice(firstBrace, lastBrace + 1);
  }

  try {
    const obj = JSON.parse(candidate);
    parsed.npcs = Array.isArray(obj.npcs) ? obj.npcs : [];
    parsed.constellations = Array.isArray(obj.constellations) ? obj.constellations : [];
    parsed.hosts = Array.isArray(obj.hosts) ? obj.hosts : [];
    parsed.contracts = Array.isArray(obj.contracts) ? obj.contracts : [];
  } catch (e) {
    parsed = { npcs: [], constellations: [], hosts: [], contracts: [] };
  }
}

function clean(value, maxLen = 500) {
  if (value === null || value === undefined) return '';
  return String(value).replace(/'/g, "''").trim().slice(0, maxLen);
}

const sessionId = String($('reply_ready').item.json.session_id || '');
const currentScene = String($('reply_ready').item.json.user_text || '').slice(0, 200);

const npcs = parsed.npcs
  .filter(n => n && n.name && String(n.name).trim() && String(n.name).trim().toLowerCase() !== 'дэниал')
  .map(n => ({
    name: clean(n.name, 120),
    role: clean(n.role, 200),
    faction: clean(n.faction, 200),
    relation: clean(n.relation, 200),
    status: clean(n.status || 'alive', 50),
    notes: clean(n.notes, 500),
    last_scene: clean(n.last_scene || currentScene, 200)
  }));

const constellations = parsed.constellations
  .filter(c => c && c.name && String(c.name).trim())
  .map(c => ({
    name: clean(c.name, 120),
    sphere: clean(c.sphere, 120),
    attitude: clean(c.attitude, 120),
    notes: clean(c.notes, 500),
    first_seen_scene: clean(c.first_seen_scene || currentScene, 200)
  }));

const hosts = parsed.hosts
  .filter(h => h && h.name && String(h.name).trim())
  .map(h => ({
    name: clean(h.name, 120),
    sector: clean(h.sector, 120),
    rank: clean(h.rank, 60),
    attitude: clean(h.attitude, 120),
    notes: clean(h.notes, 500)
  }));

const contracts = parsed.contracts
  .filter(c => c && c.title && String(c.title).trim())
  .map(c => ({
    title: clean(c.title, 200),
    constellation: clean(c.constellation, 120),
    conditions: clean(c.conditions, 500),
    rewards: clean(c.rewards, 500),
    status: clean(c.status || 'active', 60),
    notes: clean(c.notes, 500)
  }));

return {
  json: {
    session_id: sessionId,
    npcs_json: JSON.stringify(npcs),
    constellations_json: JSON.stringify(constellations),
    hosts_json: JSON.stringify(hosts),
    contracts_json: JSON.stringify(contracts),
    counts: {
      npcs: npcs.length,
      constellations: constellations.length,
      hosts: hosts.length,
      contracts: contracts.length
    }
  }
};

const item = items[0]?.json || {};
const npcs = JSON.parse(item.npcs_json || '[]');
const sessionId = item.session_id;
return npcs.map(n => ({ json: { session_id: sessionId, ...n } }));

const item = items[0]?.json || {};
const constellations = JSON.parse(item.constellations_json || '[]');
const sessionId = item.session_id;
return constellations.map(c => ({ json: { session_id: sessionId, ...c } }));

const item = items[0]?.json || {};
const hosts = JSON.parse(item.hosts_json || '[]');
const sessionId = item.session_id;
return hosts.map(h => ({ json: { session_id: sessionId, ...h } }));

const item = items[0]?.json || {};
const contracts = JSON.parse(item.contracts_json || '[]');
const sessionId = item.session_id;
return contracts.map(c => ({ json: { session_id: sessionId, ...c } }));
